<template>
  <div class="login-container">
    <el-card class="login-card">
      <h2 class="title">博客后台管理系统</h2>
      <el-form :model="form" @submit.prevent="handleLogin">
        <el-form-item>
          <el-input v-model="form.username" placeholder="用户名" prefix-icon="User" size="large" />
        </el-form-item>
        <el-form-item>
          <el-input v-model="form.password" type="password" placeholder="密码" prefix-icon="Lock" show-password size="large" />
        </el-form-item>
        <el-button type="primary" @click="handleLogin" :loading="loading" size="large" style="width: 100%">登录</el-button>
      </el-form>
    </el-card>
  </div>
</template>

<script setup>
import { ref, reactive } from 'vue';
import { useRouter } from 'vue-router';
import { ElMessage } from 'element-plus';
import request from '../api/request.js';

const router = useRouter();
const loading = ref(false);
const form = reactive({ username: '', password: '' });

const handleLogin = async () => {
  if (!form.username || !form.password) return ElMessage.warning('请输入用户名和密码');
  loading.value = true;
  try {
    const res = await request.post('/auth/login', form);
    if (res.success) {
      localStorage.setItem('token', res.token);
      ElMessage.success('登录成功');
      router.push('/');
    } else {
      ElMessage.error(res.message || '登录失败');
    }
  } catch (err) {
    console.error(err);
  } finally {
    loading.value = false;
  }
};
</script>

<style scoped>
.login-container { display: flex; justify-content: center; align-items: center; height: 100vh; background: #f0f2f5; }
.login-card { width: 420px; padding: 30px; }
.title { text-align: center; margin-bottom: 30px; color: #303133; font-size: 24px; }
</style>